// Normalise `limit` (1–20, défaut 5) — mêmes variantes que get_menu :
// { limit: 10 }, { query: '{"limit":3}' }, { query: "8" }, { query: { limit: 12 } }

const DEFAULT = 5;
const MIN = 1;
const MAX = 20;

function clampLimit(n) {
  if (!Number.isFinite(n)) return null;
  return Math.min(Math.max(Math.trunc(n), MIN), MAX);
}

function pickLimit(obj) {
  if (!obj || typeof obj !== 'object') return null;
  const v = obj.limit;
  if (v == null || v === '') return null;
  return clampLimit(Number(v));
}

const raw = $input.first().json ?? {};
let limit = pickLimit(raw);

if (limit == null && raw.query != null) {
  const q = raw.query;
  if (typeof q === 'string') {
    const s = q.trim();
    if (s.startsWith('{')) {
      try {
        limit = pickLimit(JSON.parse(s));
      } catch {
        limit = null;
      }
    } else {
      limit = clampLimit(Number(s));
    }
  } else if (typeof q === 'number') {
    limit = clampLimit(q);
  } else if (typeof q === 'object') {
    limit = pickLimit(q);
  }
}

if (limit == null) limit = DEFAULT;

return [{ json: { limit } }];

// Réponse compacte pour le LLM — ignorer les items vides (alwaysOutputData).
const rows = $input
  .all()
  .map((i) => i.json)
  .filter((j) => j && j.id != null && String(j.id).length > 0);
if (rows.length === 0) {
  return [
    {
      json: {
        items: [],
        note:
          'Aucun événement à venir (vue v_pessobot_events_upcoming vide ou date < aujourd’hui). Vérifier events.active et events.date en base.',
      },
    },
  ];
}
return [{ json: { count: rows.length, items: rows } }];
